CREATE TABLE supervisor_verifications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, institutional_email TEXT NOT NULL, institution TEXT NOT NULL, department TEXT NOT NULL, profile_link TEXT, verification_token TEXT, domain_verified BOOLEAN NOT NULL DEFAULT FALSE, status TEXT NOT NULL CHECK (status IN ('pending', 'approved', 'rejected')) DEFAULT 'pending', admin_notes TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), reviewed_at TIMESTAMPTZ);
CREATE TABLE supervisor_profiles (user_id UUID PRIMARY KEY REFERENCES users(id) ON DELETE CASCADE, research_fields JSONB DEFAULT '[]', areas_of_expertise TEXT, institutional_affiliation TEXT, availability_status TEXT NOT NULL CHECK (availability_status IN ('open', 'not_available')) DEFAULT 'not_available', mentorship_statement TEXT, updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE mentorship_requests (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), requester_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, supervisor_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, message TEXT NOT NULL, status TEXT NOT NULL CHECK (status IN ('pending', 'accepted', 'declined')) DEFAULT 'pending', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), responded_at TIMESTAMPTZ);
CREATE UNIQUE INDEX idx_mentorship_one_pending ON mentorship_requests(requester_id, supervisor_id) WHERE status = 'pending';
CREATE TABLE connections (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), requester_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, supervisor_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, connected_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE follows (follower_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, following_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), PRIMARY KEY(follower_id, following_id));
